class Solution:
    def getFinalState(self, nums, k, multiplier):
        nums = nums[:]
        for _ in range(k):
            idx = 0
            for i in range(1, len(nums)):
                if nums[i] < nums[idx]:
                    idx = i
            nums[idx] *= multiplier
        return nums

