var getFinalState = function(nums, k, multiplier) {
    const res = nums.slice();
    for (let t = 0; t < k; t++) {
        let idx = 0;
        for (let i = 1; i < res.length; i++) {
            if (res[i] < res[idx]) idx = i;
        }
        res[idx] *= multiplier;
    }
    return res;
};
